import json
import time

import google.oauth2.credentials
import google_auth_oauthlib.helpers
from google.oauth2 import service_account
from googleapiclient.discovery import build
from imdb import Cinemagoer
import imdb
from imdb.utils import analyze_title


class SuggestionsCompiler:
    def __init__(self):
        self.movies = {}
        self.suggestions = {}

    def get_suggestions_from_google_sheet(self):
        SHEET_ID = "11Y4XgDOiTcCg7YnLE97Fm9ZBAsVAdS0OvSVGEEw7PMg"
        RANGE_NAME = "B8:D"  # This is movie title and year. Adjust the range as needed
        creds = service_account.Credentials.from_service_account_file("client_secret_googleusercontent.json")

        service = build('sheets', 'v4', credentials=creds)

        # Call the Sheets API to get data
        sheet = service.spreadsheets()
        result = sheet.values().get(spreadsheetId=SHEET_ID, range=RANGE_NAME).execute()

        # Extract the data
        values = result.get('values', [])
        dict_movies = {}
        for movie in values:
            voters = movie[0].split(", ")
            # movie_title = " ".join([movie[1], movie[2]])
            movie_title = movie[1]
            movie_year = movie[2]
            dict_movies[movie_title] = {"year": movie_year, "voters": voters, "category": ""}
            self.movies[movie_title] = {"year": movie_year, "voters": voters, "category": ""}
        print("got suggestions")
        return dict_movies

    def my_movies_data(self):
        # print(self.movie_titles)
        # movie_titles = ['cabin fever', 'as above so below', 'Grave Encounters', 'The Wailing', 'Hidden',
        #                 'The Last Exorcism', 'Sputnik', 'Maniac 2012', 'Sisters 1972', 'Malum', 'The Omen', 'Body Bags',
        #                 'Resolution', 'Onibaba', 'Sleepaway Camp', '[REC]', 'Good Manners', 'Toolbox Murders',
        #                 'Tales from the Crypt 1972', 'The Midnight Meat Train', 'The Curse of Frankenstein',
        #                 'X: The Man with the X-Ray Eyes 1963', 'Asylum', 'The Hills Have Eyes', 'Frenzy',
        #                 'Kill, Baby... Kill!', 'Wolf Creek', 'The Funhouse Massacre', 'The Last House on the Left', 'Crawl',
        #                 'Wendigo', 'Dracula 3D']
        # movie_titles = ['The Host 2006', 'Onibaba 1964', 'Eyes Without a Face 1960', 'Black Sunday 1960',
        #                 'Nosferatu the Vampyre 1979', 'The Devil’s Backbone 2001', 'Freaks 1932',
        #                 'The Fly 1958', 'Repulsion 1965', 'The Wicker Man 1973',
        #                 'Hellraiser 1987', 'Candyman 1992', 'Let the Right One In 2008', 'The Witch 2015',
        #                 'Titane 2021', 'A Quiet Place 2018', '28 Days Later 2002',
        #                 'A Nightmare on Elm Street 1984', 'The Descent 2005',
        #                 'The Devil Rides Out 1968', 'Prince of Darkness 1987',
        #                 'The House That Dripped Blood 1971', 'Dracula 3000 2004',
        #                 'The Hunger 1983', 'Carrie 1976', 'The Hills Have Eyes 1977',
        #                 'The Lair of the White Worm 1988', 'Psycho 1960', 'The Endless 2017',
        #                 'Horror of Dracula 1958', 'The Mummy 1959', 'Bram Stoker’s Dracula 1992',
        #                 'Hellbound Hellraiser II 1988', 'The Mist 2007', 'Kill, Baby, Kill 1966',
        #                 'X 2022', 'The Omen 1976', 'Quatermass and the Pit 1967', 'Phenomena 1985',
        #                 'Nightbreed 1990', 'The Others 2001', 'The Brood 1979']
        # yield self.get_suggestions_from_google_sheet()

        print(self.movies)
        cache_file_reader = open('suggestions.txt', 'r')
        cache_file_writer = []
        data_cache = json.load(cache_file_reader)
        print(data_cache)
        for movie_suggestion in self.movies:
            if any(movie_suggestion in cached_movies for cached_movies in data_cache):
                print(movie_suggestion, "already on list")
            else:
                print("adding to list")
                imdby = Cinemagoer()
                combined_title_year = movie_suggestion + " " + self.movies[movie_suggestion]['year']
                search_movie = imdby.search_movie(title=combined_title_year, _episodes=False)
                query_list = []
                for x in search_movie:
                    try:
                        kind_movie = imdby.get_movie(x.movieID)["kind"]
                        if kind_movie == "movie":
                            query_list.append(x)
                    except:
                        pass
                try:
                    movie_id = query_list[0].movieID
                    movie = imdby.get_movie(movieID=movie_id, info=['main'])
                    directors = [d.get('name') for d in movie.get('director')]
                    title = movie.get('title')
                    genres = movie.get('genres')
                    cast = [a['name'] for a in movie.get('cast')]
                    countries = movie.get('countries')
                    languages = movie.get('languages')
                    year = movie.get('year')
                    story_by = [x.get('name') for x in movie.get('writer')]
                    production_companies = [c['name'] for c in movie.get('production companies')]
                    votes = len(self.movies[movie_suggestion]['voters'])
                    self.suggestions[title] = {"genres": genres, "cast": cast, "directors": directors,
                                               "production companies": production_companies, "story by": story_by,
                                               "countries": countries, "year": year, "languages": languages, "votes": votes,
                                               "movie_score": 0, "hooptober category": self.movies['']['category']}
                    append_to_cache = {title: {"genres": genres, "cast": cast, "directors": directors,
                                               "production companies": production_companies, "story by": story_by,
                                               "countries": countries, "year": year, "languages": languages, "votes": votes,
                                               "movie_score": 0, "hooptober category": self.movies[movie_suggestion]['category']}}
                    print(movie_suggestion, "data collected")
                    cache_file_reader.close()
                    print("reader closed")
                    data_cache.append(append_to_cache)
                    cache_file_writer.append(open('suggestions.txt', 'w'))
                    print("writer opened")
                    json.dump(data_cache,  cache_file_writer[-1], indent=4)
                    print("data scraping complete for", movie_suggestion)
                except:
                    print("issue scraping data for", movie_suggestion)
                time.sleep(5)
                # return self.movie_titles
            try:
                cache_file_writer[-1].close()
                print("writer closed")
            except:
                cache_file_reader.close()
                print("reader closed")
        print("done data scraping :)")

    def run_compiler(self):
        print("running")
        self.get_suggestions_from_google_sheet()
        self.my_movies_data()
        # return self.movie_titles
        print("suggestions dict", self.suggestions)
        print("complete")


SuggestionsCompiler().run_compiler()

